import React, { useState, useEffect } from 'react';
import { getEventsByOrganiser, getSlotsByEvent, getAllLocations, createSlot, updateSlot, deleteSlot } from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const STATUS_COLOR = {
  AVAILABLE: { bg: '#e8f8f2', color: '#00a86b', border: '#b2e8d0' },
  HOUSEFULL: { bg: '#fff8e6', color: '#d4900a', border: '#f0d98a' },
  CANCELLED: { bg: '#fdecea', color: '#d63b2f', border: '#f5b7b1' },
};

const TYPE_ICON = { MOVIE: '🎬', CONCERT: '🎵', EVENT: '🎭' };

// Group slots by date
const groupByDate = (slots) => {
  const map = {};
  slots.forEach((s) => {
    const key = s.showDate;
    if (!map[key]) map[key] = [];
    map[key].push(s);
  });
  return Object.entries(map).sort(([a], [b]) => new Date(a) - new Date(b));
};

const formatDate = (dateStr) => {
  const d = new Date(dateStr + 'T00:00:00');
  return {
    weekday: d.toLocaleDateString('en-IN', { weekday: 'short' }).toUpperCase(),
    day: d.getDate(),
    month: d.toLocaleDateString('en-IN', { month: 'short' }).toUpperCase(),
    year: d.getFullYear(),
    full: d.toLocaleDateString('en-IN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' }),
  };
};

const isToday = (dateStr) => {
  const today = new Date().toISOString().split('T')[0];
  return dateStr === today;
};

const isPast = (dateStr) => new Date(dateStr + 'T00:00:00') < new Date(new Date().toISOString().split('T')[0] + 'T00:00:00');

const AdminSlotsPage = () => {
  const { user } = useAuth();
  const [slots, setSlots]           = useState([]);
  const [events, setEvents]         = useState([]);
  const [locations, setLocations]   = useState([]);
  const [loading, setLoading]       = useState(true);
  const [modal, setModal]           = useState(false);
  const [editId, setEditId]         = useState(null);
  const [saving, setSaving]         = useState(false);
  const [filterEvent, setFilterEvent] = useState('');
  const [expandedDate, setExpandedDate] = useState(null);
  const [expandedSlot, setExpandedSlot] = useState(null);
  const [form, setForm] = useState({
    eventId: '', locationId: '', showDate: '', startTime: '', endTime: '', seatsLeft: '', slotStatus: 'AVAILABLE',
  });

  const load = async () => {
    setLoading(true);
    try {
      const [evRes, locRes] = await Promise.all([
        getEventsByOrganiser(user.userId),
        getAllLocations(),
      ]);
      const evs  = Array.isArray(evRes.data?.data)  ? evRes.data.data  : [];
      const locs = Array.isArray(locRes.data?.data) ? locRes.data.data : [];
      setEvents(evs);
      setLocations(locs);

      if (evs.length > 0) {
        const results = await Promise.allSettled(evs.map((e) => getSlotsByEvent(e.eventId)));
        const all = results.flatMap((r) =>
          r.status === 'fulfilled' ? (Array.isArray(r.value.data?.data) ? r.value.data.data : []) : []
        );
        const sorted = all.sort((a, b) => new Date(a.showDate) - new Date(b.showDate));
        setSlots(sorted);

        // Auto-expand nearest upcoming date
        const upcoming = sorted.find((s) => !isPast(s.showDate));
        if (upcoming) setExpandedDate(upcoming.showDate);
      } else {
        setSlots([]);
      }
    } catch { toast.error('Failed to load slots'); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, []);

  const openCreate = () => {
    setForm({ eventId: events[0]?.eventId || '', locationId: locations[0]?.locationId || '', showDate: '', startTime: '', endTime: '', seatsLeft: '', slotStatus: 'AVAILABLE' });
    setEditId(null);
    setModal(true);
  };

  const openEdit = (s, e) => {
    e.stopPropagation();
    setForm({
      eventId:    s.event?.eventId       || '',
      locationId: s.location?.locationId || '',
      showDate:   s.showDate             || '',
      startTime:  s.startTime?.slice(0, 5) || '',
      endTime:    s.endTime?.slice(0, 5)   || '',
      seatsLeft:  s.seatsLeft            || '',
      slotStatus: s.slotStatus           || 'AVAILABLE',
    });
    setEditId(s.slotId);
    setModal(true);
  };

  const save = async () => {
    if (!form.eventId || !form.locationId || !form.showDate || !form.startTime) {
      toast.error('Event, venue, date and start time are required');
      return;
    }
    setSaving(true);
    try {
      const payload = {
        ...form,
        eventId:    parseInt(form.eventId),
        locationId: parseInt(form.locationId),
        seatsLeft:  form.seatsLeft ? parseInt(form.seatsLeft) : null,
      };
      if (editId) { await updateSlot(editId, payload); toast.success('Slot updated'); }
      else        { await createSlot(payload);         toast.success('Slot created! Seats auto-assigned.'); }
      setModal(false);
      load();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to save slot'); }
    finally { setSaving(false); }
  };

  const del = async (id, e) => {
    e.stopPropagation();
    if (!window.confirm('Delete this slot?')) return;
    try { await deleteSlot(id); toast.success('Slot deleted'); load(); }
    catch (err) { toast.error(err.response?.data?.message || 'Delete failed'); }
  };

  const filtered = filterEvent ? slots.filter((s) => s.event?.eventId === parseInt(filterEvent)) : slots;
  const grouped  = groupByDate(filtered);

  const toggleDate = (date) => {
    setExpandedDate(expandedDate === date ? null : date);
    setExpandedSlot(null);
  };

  const toggleSlot = (slotId) => {
    setExpandedSlot(expandedSlot === slotId ? null : slotId);
  };

  return (
    <div style={{ background: 'var(--bg-secondary)', minHeight: '100vh', padding: '28px' }}>

      {/* ── Page Header ── */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: '12px', marginBottom: '28px' }}>
        <div>
          <h1 className="page-title" style={{ marginBottom: '4px' }}>SHOW SLOTS</h1>
          <p className="page-subtitle">Browse by date · click a date to see its shows</p>
        </div>
        <button onClick={openCreate} className="btn btn-primary">➕ Add Slot</button>
      </div>

      {/* ── Filter ── */}
      <div style={{ display: 'flex', gap: '12px', marginBottom: '28px', alignItems: 'center', flexWrap: 'wrap' }}>
        <label className="form-label" style={{ marginBottom: 0, whiteSpace: 'nowrap' }}>Filter by Event:</label>
        <select className="form-input" value={filterEvent} onChange={(e) => setFilterEvent(e.target.value)}
          style={{ width: 'auto', minWidth: '200px' }}>
          <option value="">All Events</option>
          {events.map((e) => <option key={e.eventId} value={e.eventId}>{e.name}</option>)}
        </select>
        <span style={{ fontSize: '13px', color: 'var(--text-muted)' }}>
          {filtered.length} slot{filtered.length !== 1 ? 's' : ''} across {grouped.length} date{grouped.length !== 1 ? 's' : ''}
        </span>
      </div>

      {/* ── Content ── */}
      {loading ? (
        <div className="loading-center"><div className="spinner" /></div>
      ) : grouped.length === 0 ? (
        <div className="empty-state">
          <div className="empty-state-icon">📅</div>
          <h3>No Slots Found</h3>
          <button onClick={openCreate} className="btn btn-primary" style={{ marginTop: '16px' }}>Add First Slot</button>
        </div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {grouped.map(([date, daySlots]) => {
            const df       = formatDate(date);
            const today    = isToday(date);
            const past     = isPast(date);
            const open     = expandedDate === date;
            const totalSeats = daySlots.reduce((sum, s) => sum + (s.seatsLeft || 0), 0);
            const allAvail   = daySlots.every((s) => s.slotStatus === 'AVAILABLE');
            const hasCancelled = daySlots.some((s) => s.slotStatus === 'CANCELLED');

            return (
              <div key={date} style={{
                borderRadius: '14px',
                border: `1.5px solid ${today ? 'var(--accent)' : 'var(--border)'}`,
                overflow: 'hidden',
                background: 'var(--bg-primary)',
                opacity: past ? 0.75 : 1,
                transition: 'box-shadow 0.2s',
                boxShadow: open ? '0 4px 24px rgba(0,0,0,0.08)' : '0 1px 4px rgba(0,0,0,0.04)',
              }}>

                {/* ── Date Header (clickable) ── */}
                <div onClick={() => toggleDate(date)} style={{
                  display: 'flex', alignItems: 'center', gap: '16px',
                  padding: '16px 20px', cursor: 'pointer',
                  background: open ? 'var(--bg-secondary)' : 'transparent',
                  borderBottom: open ? '1px solid var(--border)' : 'none',
                  transition: 'background 0.2s',
                }}>

                  {/* Calendar block */}
                  <div style={{
                    width: 52, height: 56, borderRadius: '10px', flexShrink: 0,
                    background: today ? 'var(--accent)' : past ? 'var(--bg-secondary)' : 'var(--bg-secondary)',
                    border: `1.5px solid ${today ? 'var(--accent)' : 'var(--border)'}`,
                    display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
                  }}>
                    <span style={{ fontSize: '10px', fontWeight: 700, letterSpacing: '0.08em', color: today ? 'rgba(255,255,255,0.85)' : 'var(--text-muted)' }}>
                      {df.weekday}
                    </span>
                    <span style={{ fontSize: '22px', fontWeight: 800, lineHeight: 1.1, color: today ? '#fff' : 'var(--text-primary)', fontFamily: 'var(--font-display)' }}>
                      {df.day}
                    </span>
                    <span style={{ fontSize: '10px', fontWeight: 600, color: today ? 'rgba(255,255,255,0.8)' : 'var(--text-muted)' }}>
                      {df.month}
                    </span>
                  </div>

                  {/* Date info */}
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', flexWrap: 'wrap' }}>
                      <span style={{ fontWeight: 700, fontSize: '15px', color: 'var(--text-primary)' }}>
                        {df.full}
                      </span>
                      {today && (
                        <span style={{ fontSize: '11px', fontWeight: 700, padding: '2px 8px', borderRadius: '20px', background: 'var(--accent)', color: '#fff' }}>
                          TODAY
                        </span>
                      )}
                      {past && (
                        <span style={{ fontSize: '11px', color: 'var(--text-muted)', fontStyle: 'italic' }}>Past</span>
                      )}
                    </div>
                    <div style={{ display: 'flex', gap: '16px', marginTop: '4px', flexWrap: 'wrap' }}>
                      <span style={{ fontSize: '12px', color: 'var(--text-muted)' }}>
                        🎭 {daySlots.length} show{daySlots.length !== 1 ? 's' : ''}
                      </span>
                      <span style={{ fontSize: '12px', color: 'var(--text-muted)' }}>
                        💺 {totalSeats} seats left
                      </span>
                      {hasCancelled && (
                        <span style={{ fontSize: '12px', color: STATUS_COLOR.CANCELLED.color }}>⚠ Some cancelled</span>
                      )}
                    </div>
                  </div>

                  {/* Show pill summaries */}
                  <div style={{ display: 'flex', gap: '6px', flexWrap: 'wrap', justifyContent: 'flex-end', flex: '0 0 auto', maxWidth: '280px' }}>
                    {daySlots.slice(0, 3).map((s) => (
                      <span key={s.slotId} style={{
                        fontSize: '11px', padding: '3px 8px', borderRadius: '20px',
                        background: STATUS_COLOR[s.slotStatus]?.bg || '#f5f5f5',
                        color: STATUS_COLOR[s.slotStatus]?.color || '#666',
                        border: `1px solid ${STATUS_COLOR[s.slotStatus]?.border || '#ddd'}`,
                        whiteSpace: 'nowrap', fontWeight: 600,
                      }}>
                        {s.startTime?.slice(0, 5)} · {s.event?.name?.length > 14 ? s.event.name.slice(0, 14) + '…' : s.event?.name}
                      </span>
                    ))}
                    {daySlots.length > 3 && (
                      <span style={{ fontSize: '11px', color: 'var(--text-muted)', padding: '3px 6px' }}>
                        +{daySlots.length - 3} more
                      </span>
                    )}
                  </div>

                  {/* Chevron */}
                  <span style={{
                    fontSize: '18px', color: 'var(--text-muted)', marginLeft: '8px', flexShrink: 0,
                    transform: open ? 'rotate(180deg)' : 'rotate(0deg)', transition: 'transform 0.25s',
                  }}>
                    ▾
                  </span>
                </div>

                {/* ── Expanded Slot List ── */}
                {open && (
                  <div style={{ padding: '16px 20px', display: 'flex', flexDirection: 'column', gap: '10px' }}>
                    {daySlots.map((s) => {
                      const sc      = STATUS_COLOR[s.slotStatus] || STATUS_COLOR.AVAILABLE;
                      const slotOpen = expandedSlot === s.slotId;

                      return (
                        <div key={s.slotId} style={{
                          borderRadius: '10px',
                          border: `1.5px solid ${slotOpen ? sc.border : 'var(--border)'}`,
                          overflow: 'hidden',
                          background: slotOpen ? sc.bg : 'var(--bg-primary)',
                          transition: 'all 0.2s',
                        }}>

                          {/* Slot row */}
                          <div onClick={() => toggleSlot(s.slotId)} style={{
                            display: 'flex', alignItems: 'center', gap: '14px',
                            padding: '14px 16px', cursor: 'pointer',
                          }}>

                            {/* Time block */}
                            <div style={{
                              flexShrink: 0, textAlign: 'center', minWidth: '72px',
                              padding: '6px 10px', borderRadius: '8px',
                              background: 'var(--bg-secondary)',
                              border: '1px solid var(--border)',
                            }}>
                              <div style={{ fontSize: '15px', fontWeight: 800, fontFamily: 'var(--font-mono, monospace)', color: 'var(--text-primary)', letterSpacing: '-0.02em' }}>
                                {s.startTime?.slice(0, 5)}
                              </div>
                              {s.endTime && (
                                <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginTop: '1px' }}>
                                  – {s.endTime.slice(0, 5)}
                                </div>
                              )}
                            </div>

                            {/* Event info */}
                            <div style={{ flex: 1, minWidth: 0 }}>
                              <div style={{ display: 'flex', alignItems: 'center', gap: '7px', flexWrap: 'wrap' }}>
                                <span style={{ fontSize: '16px' }}>
                                  {TYPE_ICON[s.event?.type] || '🎭'}
                                </span>
                                <span style={{ fontWeight: 700, fontSize: '15px', color: 'var(--text-primary)' }}>
                                  {s.event?.name}
                                </span>
                                <span style={{
                                  fontSize: '10px', fontWeight: 700, padding: '2px 7px', borderRadius: '20px',
                                  background: sc.bg, color: sc.color, border: `1px solid ${sc.border}`,
                                }}>
                                  {s.slotStatus}
                                </span>
                              </div>
                              <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '3px', display: 'flex', gap: '14px', flexWrap: 'wrap' }}>
                                <span>📍 {s.location?.locName}</span>
                                <span style={{ color: s.seatsLeft > 20 ? 'var(--green)' : s.seatsLeft > 0 ? 'var(--gold)' : 'var(--accent)', fontWeight: 600 }}>
                                  💺 {s.seatsLeft} left
                                </span>
                                {s.event?.genre && <span>🎭 {s.event.genre}</span>}
                                {s.event?.language && <span>🌐 {s.event.language}</span>}
                              </div>
                            </div>

                            {/* Actions */}
                            <div style={{ display: 'flex', gap: '6px', flexShrink: 0 }} onClick={(e) => e.stopPropagation()}>
                              <button onClick={(e) => openEdit(s, e)} className="btn btn-secondary btn-sm">Edit</button>
                              <button onClick={(e) => del(s.slotId, e)} className="btn btn-danger btn-sm">Delete</button>
                            </div>

                            <span style={{
                              fontSize: '14px', color: 'var(--text-muted)', flexShrink: 0,
                              transform: slotOpen ? 'rotate(180deg)' : 'rotate(0deg)', transition: 'transform 0.2s',
                            }}>
                              ▾
                            </span>
                          </div>

                          {/* Expanded slot detail */}
                          {slotOpen && (
                            <div style={{
                              borderTop: `1px dashed ${sc.border}`,
                              padding: '14px 16px',
                              display: 'grid',
                              gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))',
                              gap: '12px',
                              background: 'var(--bg-primary)',
                            }}>
                              {[
                                { label: 'Slot ID',    value: `#${s.slotId}` },
                                { label: 'Event Type', value: `${TYPE_ICON[s.event?.type] || ''} ${s.event?.type || '—'}` },
                                { label: 'Duration',   value: s.event?.duration || '—' },
                                { label: 'Category',   value: s.event?.categoryName || '—' },
                                { label: 'Venue',      value: s.location?.locName || '—' },
                                { label: 'Seats Left', value: s.seatsLeft ?? '—', highlight: true },
                              ].map(({ label, value, highlight }) => (
                                <div key={label} style={{
                                  padding: '10px 12px', borderRadius: '8px',
                                  background: 'var(--bg-secondary)',
                                  border: '1px solid var(--border)',
                                }}>
                                  <div style={{ fontSize: '10px', color: 'var(--text-muted)', fontWeight: 700, letterSpacing: '0.06em', marginBottom: '3px' }}>
                                    {label.toUpperCase()}
                                  </div>
                                  <div style={{ fontSize: '14px', fontWeight: 600, color: highlight ? sc.color : 'var(--text-primary)' }}>
                                    {value}
                                  </div>
                                </div>
                              ))}
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* ── Modal ── */}
      {modal && (
        <div className="modal-overlay" onClick={() => setModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">{editId ? 'EDIT SLOT' : 'ADD SHOW SLOT'}</h3>
              <button className="modal-close" onClick={() => setModal(false)}>✕</button>
            </div>
            <div className="form-group">
              <label className="form-label">Event *</label>
              <select className="form-input" value={form.eventId} onChange={(e) => setForm((f) => ({ ...f, eventId: e.target.value }))}>
                <option value="">Select event</option>
                {events.map((e) => <option key={e.eventId} value={e.eventId}>{e.name}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Venue *</label>
              <select className="form-input" value={form.locationId} onChange={(e) => setForm((f) => ({ ...f, locationId: e.target.value }))}>
                <option value="">Select venue</option>
                {locations.map((l) => <option key={l.locationId} value={l.locationId}>{l.locName} – {l.address}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Show Date *</label>
              <input type="date" className="form-input" value={form.showDate} onChange={(e) => setForm((f) => ({ ...f, showDate: e.target.value }))} />
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
              <div className="form-group">
                <label className="form-label">Start Time *</label>
                <input type="time" className="form-input" value={form.startTime} onChange={(e) => setForm((f) => ({ ...f, startTime: e.target.value }))} />
              </div>
              <div className="form-group">
                <label className="form-label">End Time</label>
                <input type="time" className="form-input" value={form.endTime} onChange={(e) => setForm((f) => ({ ...f, endTime: e.target.value }))} />
              </div>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
              <div className="form-group">
                <label className="form-label">Seats (blank = auto)</label>
                <input type="number" className="form-input" value={form.seatsLeft} onChange={(e) => setForm((f) => ({ ...f, seatsLeft: e.target.value }))} placeholder="Auto from venue" />
              </div>
              <div className="form-group">
                <label className="form-label">Status</label>
                <select className="form-input" value={form.slotStatus} onChange={(e) => setForm((f) => ({ ...f, slotStatus: e.target.value }))}>
                  {['AVAILABLE', 'HOUSEFULL', 'CANCELLED'].map((s) => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            </div>
            {!editId && (
              <div style={{ padding: '10px 14px', background: 'var(--green-dim)', borderRadius: '8px', border: '1px solid rgba(0,214,143,0.2)', fontSize: '13px', color: 'var(--green)', marginBottom: '16px' }}>
                💡 Creating a slot will auto-generate seat entries from the venue's seat layout
              </div>
            )}
            <div style={{ display: 'flex', gap: '12px' }}>
              <button onClick={() => setModal(false)} className="btn btn-secondary" style={{ flex: 1 }}>Cancel</button>
              <button onClick={save} disabled={saving} className="btn btn-primary" style={{ flex: 2 }}>
                {saving ? 'Saving...' : editId ? 'Update Slot' : 'Create Slot'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminSlotsPage;
